-- ============================================================
-- PitLane（F1 25 玩家社区平台） — 数据库结构
-- 在 Supabase Dashboard → SQL Editor 中整体执行一次
-- ============================================================

-- ---------- 枚举 ----------
create type platform_type as enum ('PC', 'PS', 'Xbox');
create type room_type as enum ('career_duo', 'grand_prix');
create type room_status as enum ('open', 'closed', 'expired');
create type application_status as enum ('pending', 'accepted', 'rejected', 'withdrawn');

-- ---------- 用户资料 ----------
create table public.profiles (
  id uuid primary key references auth.users(id) on delete cascade,
  nickname text not null check (char_length(nickname) between 1 and 20),
  platform platform_type not null default 'PC',
  qq text check (qq ~ '^[0-9]{5,12}$'),  -- 仅本人可读，见 RLS
  created_at timestamptz not null default now()
);

-- 注册后自动建 profile
create or replace function public.handle_new_user()
returns trigger language plpgsql security definer set search_path = public as $$
begin
  insert into public.profiles (id, nickname)
  values (new.id, coalesce(new.raw_user_meta_data->>'nickname', '车手' || left(new.id::text, 6)));
  return new;
end; $$;

create trigger on_auth_user_created
  after insert on auth.users
  for each row execute function public.handle_new_user();

-- ---------- 赛道 ----------
create table public.tracks (
  id serial primary key,
  name_zh text not null,
  name_en text not null,
  country text not null,
  baseline_time_ms int not null,          -- 对应 baseline_difficulty 的圈速（毫秒），即 difficulty_curve_ms 的第 111 个元素
  baseline_difficulty int not null default 110 check (baseline_difficulty between 0 and 110),
  -- 难度 0→110 的完整圈速曲线（111 个点，下标 1=难度0 ... 下标 111=难度110），
  -- 用于 calc_difficulty() 精确插值；为空时退回比例公式兜底
  difficulty_curve_ms int[] check (difficulty_curve_ms is null or array_length(difficulty_curve_ms, 1) = 111),
  is_active boolean not null default true
);

-- 种子数据：F1 25 全部 24 条赛道（按 2025 赛季日历顺序）
-- baseline_time_ms 取自 F1Laps.com 每条赛道计算器页面内嵌的难度曲线（见下方 difficulty_curve_ms 数据，
-- 第 111 个点即难度 110 对应圈速），来源 https://www.f1laps.com/f1-25/ai-difficulty-calculator/<track>/
