-- ---------- 圈速 ----------
create table public.lap_times (
  id bigserial primary key,
  user_id uuid not null references public.profiles(id) on delete cascade,
  track_id int not null references public.tracks(id),
  time_ms int not null check (time_ms between 40000 and 300000),
  suggested_difficulty int not null check (suggested_difficulty between 0 and 110),
  updated_at timestamptz not null default now(),
  unique (user_id, track_id)
);

-- 难度计算函数（前端也有同样逻辑，这里做兜底：入库时以数据库计算为准）
-- 优先用 tracks.difficulty_curve_ms 里的完整实测曲线（111 个点，对应难度 0..110）做线性插值，
-- 精度远高于比例公式；赛道没有曲线数据时，退回「基准圈速按 16.27% 比例缩放」的近似公式兜底
-- （该比例数据来源见 lib/laptime.ts 顶部注释）
create or replace function public.calc_difficulty(p_track_id int, p_time_ms int)
returns int language plpgsql stable as $$
declare
  curve int[];
  baseline_ms int;
  baseline_diff int;
  i int;
  frac numeric;
begin
  select difficulty_curve_ms, baseline_time_ms, baseline_difficulty
    into curve, baseline_ms, baseline_diff
    from public.tracks where id = p_track_id;

  if curve is null then
    return greatest(0, least(110,
      round(
        baseline_diff - (p_time_ms - baseline_ms) / (baseline_ms * 0.1627 / 110)
      )::int
    ));
  end if;

  -- curve[1] = 难度0（最慢），curve[111] = 难度110（最快）
  if p_time_ms <= curve[111] then
    return 110;
  end if;
  if p_time_ms >= curve[1] then
    return 0;
  end if;

  for i in 1..110 loop
    if curve[i] >= p_time_ms and p_time_ms >= curve[i + 1] then
      frac := (curve[i] - p_time_ms)::numeric / (curve[i] - curve[i + 1]);
      return round((i - 1) + frac)::int;
    end if;
  end loop;

  return 55; -- 理论上不会走到这里
end;
$$;

create or replace function public.lap_times_set_difficulty()
returns trigger language plpgsql as $$
begin
  new.suggested_difficulty := public.calc_difficulty(new.track_id, new.time_ms);
  new.updated_at := now();
  return new;
end; $$;

create trigger trg_lap_times_difficulty
  before insert or update on public.lap_times
  for each row execute function public.lap_times_set_difficulty();

-- 玩家综合建议难度视图
create or replace view public.player_overall_difficulty as
  select user_id,
         round(avg(suggested_difficulty))::int as overall_difficulty,
         count(*) as tracks_count
  from public.lap_times
  group by user_id;

-- ---------- 房间（双人生涯 + 大奖赛共用） ----------
create table public.rooms (
  id bigserial primary key,
  type room_type not null,
  host_id uuid not null references public.profiles(id) on delete cascade,
  title text not null check (char_length(title) between 1 and 50),
  description text check (char_length(description) <= 1000),
  platform platform_type not null,
  min_difficulty int check (min_difficulty between 0 and 110),  -- 软门槛，可空
  max_players int not null default 2 check (max_players between 2 and 22),
  event_time timestamptz,          -- 大奖赛：比赛时间；生涯帖可空
  track_id int references public.tracks(id),  -- 大奖赛可选
  voice_room_code text check (char_length(voice_room_code) <= 50),  -- Oopz/KOOK 房间码，仅大奖赛
  status room_status not null default 'open',
  expires_at timestamptz not null default now() + interval '14 days',
  created_at timestamptz not null default now(),
  constraint career_duo_two_players check (type <> 'career_duo' or max_players = 2)
);

create index idx_rooms_list on public.rooms (type, status, created_at desc);

-- ---------- 申请 / 报名 ----------
create table public.room_applications (
  id bigserial primary key,
  room_id bigint not null references public.rooms(id) on delete cascade,
  user_id uuid not null references public.profiles(id) on delete cascade,
  message text check (char_length(message) <= 200),
  snapshot_difficulty int,         -- 申请时的综合难度快照（可空=无数据）
  status application_status not null default 'pending',
  created_at timestamptz not null default now(),
  unique (room_id, user_id)
);

-- 申请时自动快照综合难度；大奖赛默认直接 accepted（报名制）
create or replace function public.applications_before_insert()
returns trigger language plpgsql security definer set search_path = public as $$
declare v_type room_type;
begin
  select overall_difficulty into new.snapshot_difficulty
    from public.player_overall_difficulty where user_id = new.user_id;
  select type into v_type from public.rooms where id = new.room_id;
  if v_type = 'grand_prix' then
    new.status := 'accepted';
  end if;
  return new;
end; $$;

create trigger trg_applications_snapshot
  before insert on public.room_applications
  for each row execute function public.applications_before_insert();

-- ---------- RLS ----------
alter table public.profiles enable row level security;
alter table public.tracks enable row level security;
alter table public.lap_times enable row level security;
alter table public.rooms enable row level security;
alter table public.room_applications enable row level security;

-- profiles：所有人可读（qq 字段通过公开视图隐藏，见下）；本人可改
create policy "profiles_select_all" on public.profiles for select using (true);
create policy "profiles_update_own" on public.profiles for update using (auth.uid() = id);

-- ⚠️ 前端列表/主页一律查 public_profiles 视图（不含 qq），不要直查 profiles
create or replace view public.public_profiles as
  select id, nickname, platform, created_at from public.profiles;

-- tracks：公开只读（改数据走 Dashboard）
create policy "tracks_select_all" on public.tracks for select using (true);

-- lap_times：公开可读，本人可写
create policy "lap_select_all" on public.lap_times for select using (true);
create policy "lap_insert_own" on public.lap_times for insert with check (auth.uid() = user_id);
create policy "lap_update_own" on public.lap_times for update using (auth.uid() = user_id);
create policy "lap_delete_own" on public.lap_times for delete using (auth.uid() = user_id);

-- rooms：公开可读（voice_room_code 用函数按关系取，前端列表查询时不 select 该列），房主可写
create policy "rooms_select_all" on public.rooms for select using (true);
create policy "rooms_insert_own" on public.rooms for insert with check (auth.uid() = host_id);
create policy "rooms_update_own" on public.rooms for update using (auth.uid() = host_id);
create policy "rooms_delete_own" on public.rooms for delete using (auth.uid() = host_id);

-- applications：双人生涯仅房主与本人可读；大奖赛报名列表对所有人公开（见 ARCHITECTURE.md 3.3 节）
create policy "app_select_related" on public.room_applications for select
  using (auth.uid() = user_id
     or auth.uid() = (select host_id from public.rooms r where r.id = room_id)
     or (select type from public.rooms r where r.id = room_id) = 'grand_prix');
create policy "app_insert_own" on public.room_applications for insert
  with check (auth.uid() = user_id);
create policy "app_update_own_withdraw" on public.room_applications for update
  using (auth.uid() = user_id);
create policy "app_update_host" on public.room_applications for update
  using (auth.uid() = (select host_id from public.rooms r where r.id = room_id));

-- ---------- 敏感信息按关系放行（security definer 函数） ----------

-- 大奖赛房间码：房主或已 accepted 的报名者可取
create or replace function public.get_room_code(p_room_id bigint)
returns text language plpgsql security definer set search_path = public as $$
declare v_code text;
begin
  select voice_room_code into v_code from public.rooms r
  where r.id = p_room_id
    and (r.host_id = auth.uid()
      or exists (select 1 from public.room_applications a
                 where a.room_id = p_room_id and a.user_id = auth.uid()
                   and a.status = 'accepted'));
  return v_code;  -- 无权限返回 null
end; $$;

-- 双人生涯 QQ 互见：与我在同一房间形成 accepted 关系的对方 QQ
create or replace function public.get_partner_qq(p_room_id bigint)
returns table (user_id uuid, qq text) language plpgsql security definer set search_path = public as $$
begin
  return query
  select p.id, p.qq
  from public.rooms r
  join public.room_applications a on a.room_id = r.id and a.status = 'accepted'
  join public.profiles p on p.id in (r.host_id, a.user_id) and p.id <> auth.uid()
  where r.id = p_room_id
    and r.type = 'career_duo'
    and (r.host_id = auth.uid() or a.user_id = auth.uid());
end; $$;
